import { useAppStore } from "../store/appStore";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const pct = (v) => `${(v ?? 0).toFixed(1)}%`;
const usd = (v) => `$${Math.abs(v).toLocaleString("en-US", { minimumFractionDigits: 0 })}`;

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, t = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${t}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── breakdown bar ───────────────────────────────────── */
function BreakdownBar({ items }) {
  return (
    <div>
      <div style={{ display: "flex", height: 20, borderRadius: 6, overflow: "hidden", marginBottom: 12 }}>
        {items.map(item => (
          <div key={item.name} title={`${item.name}: ${item.pct}%`} style={{
            flex: item.pct,
            background: item?.color || "rgba(150,190,255,0.6)",
            display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: 10, fontWeight: 600, color: "rgba(0,0,0,0.7)",
          }}>
            {item.pct >= 12 ? `${item.pct}%` : ""}
          </div>
        ))}
      </div>
      {items.map(item => (
        <div key={item.name} style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 8 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8, fontSize: 13 }}>
            <div style={{ width: 10, height: 10, borderRadius: 6, background: item?.color || "rgba(150,190,255,0.6)" }} />
            <span>{item.name}</span>
          </div>
          <span className="v2-mono" style={{ fontSize: 13 }}>{item.pct}%</span>
        </div>
      ))}
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function RiskAttribution() {
  const { state } = useAppStore();

  /* poll risk exposure + v2 attribution data */
  const { data: exposureData, loading } = usePoll(
    async () => {
      const [expRes, attrRes] = await Promise.all([
        http.get("/risk/exposure"),
        http.get("/v2/risk-attribution").catch(() => ({ data: {} })),
      ]);
      const raw = expRes.data || {};
      const attr = attrRes.data || {};
      /* build strategy-level risk from exposure bots */
      const strategies = (raw.exposure || []).map(b => ({
        name: b.bot_name,
        positions: b.positions_count || 0,
        exposure: Math.abs(b.positions_value || 0),
        contribution: raw.total_equity > 0 ? ((Math.abs(b.positions_value || 0) / raw.total_equity) * 100) : 0,
        varContrib: null,
      }));
      /* build factor breakdown from v2 attribution */
      const factors = (attr.by_factor || []).map(f => ({
        name: f.factor,
        exposure: f.contribution_pct || 0,
        contrib: (f.contribution_pct || 0) * 100,
        direction: f.pnl >= 0 ? "Long" : "Short",
      }));
      return { strategies, symbols: attr.by_position || [], sectors: [], regions: [], factors };
    },
    { intervalMs: 15000, immediate: true, enabled: !state.offlineMode }
  );

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Risk Attribution</h1>
            <div className="v2-muted">Loading attribution data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  if (!exposureData) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">Risk Attribution</h1>
            <div className="v2-muted">Where risk concentrates: strategy, symbol, sector, region, and factor decomposition.</div>
          </div>
        </div>
        <V2EmptyState icon="\u29C6" title="No Risk Data" message="Waiting for live risk exposure data from the API." />
      </>
    );
  }

  /* Derive data from exposureData when available */
  const strategyRisk = Array.isArray(exposureData?.strategies) ? exposureData.strategies : [];
  const symbolRisk = Array.isArray(exposureData?.symbols) ? exposureData.symbols : [];
  const sectors = Array.isArray(exposureData?.sectors) ? exposureData.sectors : [];
  const regions = Array.isArray(exposureData?.regions) ? exposureData.regions : [];
  const factors = Array.isArray(exposureData?.factors) ? exposureData.factors : [];

  return (
    <>
      {/* ── header ────────────────────────────────────── */}
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">Risk Attribution</h1>
          <div className="v2-muted">Where risk concentrates: strategy, symbol, sector, region, and factor decomposition.</div>
        </div>
      </div>

      {/* ── top stats ─────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Largest Single Risk" value={"\u2014"} t="blue" sub="Waiting for strategy risk data" />
        <Stat label="Sector Concentration" value={"\u2014"} t="blue" sub="Waiting for sector data" />
        <Stat label="Region Concentration" value={"\u2014"} t="blue" sub="Waiting for region data" />
        <Stat label="Active Strategies" value={strategyRisk.length || "\u2014"} t="blue" sub="Contributing to risk" />
      </div>

      {/* ── by-strategy risk table ────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Risk Attribution by Strategy</div>
          {strategyRisk.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Strategy Risk Data" message="Strategy-level risk attribution will appear when the risk API provides strategy breakdowns." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "180px 80px 110px 110px 100px 1fr" }}>
                <span>Strategy</span>
                <span style={{ textAlign: "right" }}># Pos</span>
                <span style={{ textAlign: "right" }}>Exposure</span>
                <span style={{ textAlign: "right" }}>Contribution</span>
                <span style={{ textAlign: "right" }}>VaR Contrib</span>
                <span>Risk Weight</span>
              </div>
              {strategyRisk.map(s => (
                <div key={s.name} className="v2-tr" style={{
                  gridTemplateColumns: "180px 80px 110px 110px 100px 1fr",
                  alignItems: "center",
                }}>
                  <span style={{ fontWeight: 500, fontSize: 13 }}>{s.name}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.positions ?? "\u2014"}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.exposure != null ? usd(s.exposure) : "\u2014"}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.contribution != null ? pct(s.contribution) : "\u2014"}</span>
                  <span className="v2-mono v2-red" style={{ textAlign: "right" }}>{s.varContrib != null ? usd(s.varContrib) : "\u2014"}</span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ flex: 1, height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%",
                        width: `${Math.min((s.contribution || 0) / 25 * 100, 100)}%`,
                        borderRadius: 6,
                        background: "linear-gradient(90deg, rgba(150,190,255,0.5), rgba(150,190,255,0.2))",
                        transition: "width 0.4s ease",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* ── by-symbol risk table ──────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card wide">
          <div className="v2-ct">Risk Attribution by Symbol</div>
          {symbolRisk.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Symbol Risk Data" message="Symbol-level risk attribution will appear when position data includes risk metrics." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "80px 80px 80px 100px 100px 1fr" }}>
                <span>Symbol</span>
                <span style={{ textAlign: "right" }}>Weight</span>
                <span style={{ textAlign: "right" }}>Beta</span>
                <span style={{ textAlign: "right" }}>Vol Contrib</span>
                <span style={{ textAlign: "right" }}>Marginal VaR</span>
                <span>Beta Exposure</span>
              </div>
              {symbolRisk.map(s => (
                <div key={s.symbol} className="v2-tr" style={{
                  gridTemplateColumns: "80px 80px 80px 100px 100px 1fr",
                  alignItems: "center",
                }}>
                  <span className="v2-mono" style={{ fontWeight: 600 }}>{s.symbol}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.weight != null ? pct(s.weight) : "\u2014"}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.beta != null ? s.beta.toFixed(2) : "\u2014"}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{s.volContrib != null ? pct(s.volContrib) : "\u2014"}</span>
                  <span className="v2-mono v2-red" style={{ textAlign: "right" }}>{s.marginalVaR != null ? usd(s.marginalVaR) : "\u2014"}</span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ flex: 1, height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%",
                        width: `${Math.min((s.beta || 0) / 2 * 100, 100)}%`,
                        borderRadius: 6,
                        background: "linear-gradient(90deg, rgba(150,190,255,0.5), rgba(110,240,180,0.3))",
                        transition: "width 0.4s ease",
                      }} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>

      {/* ── sector + region breakdowns ────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <div className="v2-card half">
          <div className="v2-ct">By Sector Breakdown</div>
          {sectors.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Sector Data" message="Sector breakdown will appear when the risk API provides sector allocations." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <BreakdownBar items={sectors} />
            </div>
          )}
        </div>

        <div className="v2-card half">
          <div className="v2-ct">By Region Breakdown</div>
          {regions.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Region Data" message="Region breakdown will appear when the risk API provides region allocations." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <BreakdownBar items={regions} />
            </div>
          )}
        </div>
      </div>

      {/* ── risk factor decomposition ─────────────────── */}
      <div className="v2-grid">
        <div className="v2-card wide">
          <div className="v2-ct">Risk Factor Decomposition</div>
          {factors.length === 0 ? (
            <V2EmptyState icon="\u29C6" title="No Factor Data" message="Factor decomposition (Market, Size, Value, Momentum) will appear when the risk API provides factor exposures." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "180px 100px 100px 140px 1fr" }}>
                <span>Factor</span>
                <span style={{ textAlign: "right" }}>Exposure</span>
                <span style={{ textAlign: "right" }}>Risk Contrib</span>
                <span>Direction</span>
                <span>Contribution Bar</span>
              </div>
              {factors.map(f => (
                <div key={f.name} className="v2-tr" style={{ gridTemplateColumns: "180px 100px 100px 140px 1fr", alignItems: "center" }}>
                  <span style={{ fontWeight: 500, fontSize: 13 }}>{f.name}</span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>
                    {f.exposure != null ? f.exposure.toFixed(2) : "N/A"}
                  </span>
                  <span className="v2-mono" style={{ textAlign: "right" }}>{f.contrib != null ? pct(f.contrib) : "\u2014"}</span>
                  <span>
                    <span className="v2-pill" style={{ fontSize: 10 }}>{f.direction || "\u2014"}</span>
                  </span>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <div style={{ flex: 1, height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%",
                        width: `${Math.min((f.contrib || 0) / 70 * 100, 100)}%`,
                        borderRadius: 6,
                        background: "rgba(150,190,255,0.4)",
                        transition: "width 0.4s ease",
                      }} />
                    </div>
                    <span className="v2-mono" style={{ fontSize: 11, minWidth: 36, textAlign: "right" }}>{f.contrib != null ? pct(f.contrib) : "\u2014"}</span>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
